import React from 'react';
import { Link } from 'react-router-dom';

export default function Home() {
  return (
    <div>

      {/* ── HERO ── */}
      <section style={{
        position:'relative', minHeight:'100vh',
        display:'flex', alignItems:'center', overflow:'hidden',
      }}>
        {/* Background photo — desktop: TEDx wide shot, mobile: headshot */}
        <div className="hero-bg" style={{
          position:'absolute', inset:0,
          backgroundSize:'cover', backgroundPosition:'40% center',
          zIndex:0,
        }} />
        <style>{`
          .hero-bg { background-image: url(/images/fayzan-ted.jpg); }
          @media (max-width: 768px) {
            .hero-bg {
              background-image: none !important;
              background: linear-gradient(135deg, #1a0900, #3b1007, #92400e, #b45309, #431407, #1a0900);
              background-size: 400% 400%;
              animation: heroShift 10s ease infinite;
            }
          }
          @keyframes heroShift {
            0%   { background-position: 0% 50%; }
            50%  { background-position: 100% 50%; }
            100% { background-position: 0% 50%; }
          }
        `}</style>
        {/* Dark gradient */}
        <div style={{
          position:'absolute', inset:0,
          background:'linear-gradient(110deg, rgba(10,7,0,0.93) 0%, rgba(26,14,0,0.82) 50%, rgba(10,7,0,0.60) 100%)',
          zIndex:1,
        }} />
        {/* Warm orbs */}
        <div className="orb" style={{ zIndex:1, width:560, height:560, bottom:'-80px', left:'-80px', background:'radial-gradient(circle,rgba(245,158,11,0.18) 0%,transparent 68%)' }} />
        <div className="orb" style={{ zIndex:1, width:400, height:400, top:'10%', right:'12%', background:'radial-gradient(circle,rgba(234,108,30,0.10) 0%,transparent 70%)' }} />

        <div className="container" style={{ position:'relative', zIndex:2, paddingTop:'130px', paddingBottom:'100px' }}>
          <span className="label">Fayzan Rab, MD PCC</span>
          <h1 style={{
            fontSize:'clamp(38px,5.5vw,70px)',
            fontWeight:500, fontStyle:'italic',
            lineHeight:1.10, maxWidth:'660px',
            marginBottom:'24px',
          }}>
            Executive Coach and Physician focused on{' '}
            <span style={{
              background:'linear-gradient(135deg,#fbbf24,#f59e0b,#ea6c1e)',
              WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', backgroundClip:'text',
            }}>unlocking human potential</span>
          </h1>
          <p style={{ fontSize:'16px', color:'var(--text-2)', lineHeight:'1.72', maxWidth:'460px', marginBottom:'36px' }}>
            A physician and executive coach synthesizing medicine, technology, and behavioral science to help high performers lead at their ceiling.
          </p>
          <div style={{ display:'flex', gap:'12px', flexWrap:'wrap', marginBottom:'52px' }}>
            <Link to="/contact" className="btn btn-primary">Work with me →</Link>
            <Link to="/about" className="btn btn-outline">Learn more</Link>
          </div>
          <div className="stats-badge">
            <span className="stats-number">1,000+</span>
            <span className="stats-label">coaching hours with high performers</span>
          </div>
        </div>
      </section>

      {/* ── LOGO STRIP ── */}
      <div className="logo-strip">
        <div className="container">
          <div className="logo-strip-inner">
            {['MD, Emory University','PCC Certified (ICF)','TEDx Speaker','1,000+ Coaching Hours'].map(item => (
              <span key={item} className="logo-strip-item">{item}</span>
            ))}
          </div>
        </div>
      </div>

      {/* ── JOURNEY ── */}
      <section className="section">
        <div className="container">
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'72px', alignItems:'center' }} className="two-col">

            {/* Photo */}
            <div style={{ position:'relative', order:0 }}>
              <div className="orb" style={{ width:340, height:340, top:'-40px', left:'-40px', background:'radial-gradient(circle,rgba(245,158,11,0.14) 0%,transparent 70%)', zIndex:0 }} />
              <div style={{ position:'relative', borderRadius:'20px', overflow:'hidden', zIndex:1 }}>
                <img
                  src="/images/fayz.jpg"
                  alt="Fayzan Rab"
                  style={{ width:'100%', height:'460px', objectFit:'cover', objectPosition:'top center' }}
                />
                {/* Warm amber tint */}
                <div style={{
                  position:'absolute', inset:0,
                  background:'linear-gradient(160deg,rgba(245,158,11,0.16) 0%,rgba(120,53,15,0.30) 100%)',
                  mixBlendMode:'multiply',
                }} />
                <div style={{
                  position:'absolute', inset:0,
                  border:'1px solid rgba(245,158,11,0.14)',
                  borderRadius:'20px',
                }} />
              </div>
            </div>

            {/* Text */}
            <div>
              <span className="label">The Journey</span>
              <h2 style={{ fontSize:'clamp(26px,3vw,40px)', fontStyle:'italic', fontWeight:500, marginBottom:'20px' }}>
                I was doing everything right — and it wasn't enough.
              </h2>
              <p style={{ color:'var(--text-2)', lineHeight:'1.85', marginBottom:'16px', fontSize:'15px' }}>
                Product leader at Google. Series C biotech startup. Successful by every external measure — but unclear on what the highest utilization of my gifts would actually look like.
              </p>
              <p style={{ color:'var(--text-2)', lineHeight:'1.85', marginBottom:'30px', fontSize:'15px' }}>
                I tried many things before stumbling into executive coaching. Then went to medical school and accumulated thousands of hours working with high performers. The synthesis is the work.
              </p>
              <Link to="/about" style={{
                display:'inline-flex', alignItems:'center', gap:'6px',
                fontSize:'11.5px', fontWeight:700, letterSpacing:'0.12em',
                textTransform:'uppercase', color:'var(--amber)',
              }}>Read the full story →</Link>
            </div>
          </div>
        </div>
      </section>

      {/* ── IRREPLACEABLE ── */}
      <section style={{ position:'relative', overflow:'hidden', padding:'100px 0' }}>
        <div className="orb" style={{ width:600, height:400, top:'50%', left:'50%', transform:'translate(-50%,-50%)', background:'radial-gradient(ellipse,rgba(245,158,11,0.08) 0%,transparent 70%)' }} />
        <div className="container" style={{ position:'relative', zIndex:1, textAlign:'center', maxWidth:'700px', margin:'0 auto' }}>
          <span className="label">The Irreplaceable Part</span>
          <p style={{
            fontSize:'clamp(18px,2.3vw,27px)',
            fontFamily:"'Lora',serif", fontStyle:'italic',
            fontWeight:400, lineHeight:'1.62',
            color:'var(--text)', marginBottom:'18px',
          }}>
            "You're already surrounded by tools that optimize, analyze, and advise. What's harder to find is someone who actually knows you — who remembers what you said six months ago, notices when something's off, and stays with you through the messy middle."
          </p>
          <p style={{ fontSize:'13px', color:'var(--text-3)' }}>
            Fayzan works with a small number of clients at a time — by design. The relationship is the work.
          </p>
        </div>
      </section>

      {/* ── SERVICES ── */}
      <section className="section" style={{ paddingTop:0 }}>
        <div className="container">
          <span className="label" style={{ display:'block', textAlign:'center' }}>What's Offered</span>
          <h2 style={{ fontSize:'clamp(26px,3vw,40px)', fontStyle:'italic', fontWeight:500, textAlign:'center', marginBottom:'44px' }}>
            How Fayzan works
          </h2>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'18px' }} className="two-col">
            <div className="service-card service-card-1">
              <span style={{ display:'inline-block', fontSize:'10px', fontWeight:700, letterSpacing:'0.14em', textTransform:'uppercase', color:'rgba(255,255,255,0.55)', marginBottom:'14px' }}>1:1 Executive Coaching</span>
              <h3>1:1 Executive Coaching</h3>
              <p>Ongoing, high-touch engagement. The relationship deepens over time — and so does the work. Fayzan keeps a deliberately small roster.</p>
              <Link to="/coaching" className="learn-more">Learn More →</Link>
            </div>
            <div className="service-card service-card-2">
              <span style={{ display:'inline-block', fontSize:'10px', fontWeight:700, letterSpacing:'0.14em', textTransform:'uppercase', color:'rgba(255,255,255,0.55)', marginBottom:'14px' }}>Co-Founder Mediation</span>
              <h3>Co-Founder Mediation</h3>
              <p>A structured process for founding teams in conflict. Individual and joint sessions — designed to restore trust and find a clear path forward.</p>
              <Link to="/coaching" className="learn-more">Learn More →</Link>
            </div>
          </div>
        </div>
      </section>

      {/* ── PULL QUOTE ── */}
      <section style={{
        position:'relative', overflow:'hidden',
        padding:'100px 0',
        background:'linear-gradient(135deg,rgba(245,158,11,0.05) 0%,rgba(234,108,30,0.07) 100%)',
      }}>
        <div className="orb" style={{ width:400, height:400, top:'-80px', right:'-60px', background:'radial-gradient(circle,rgba(245,158,11,0.12) 0%,transparent 70%)' }} />
        <div className="orb" style={{ width:300, height:300, bottom:'-60px', left:'-40px', background:'radial-gradient(circle,rgba(234,108,30,0.10) 0%,transparent 70%)' }} />
        <div className="container" style={{ textAlign:'center', maxWidth:'640px', margin:'0 auto', position:'relative', zIndex:1 }}>
          <div style={{ width:'36px', height:'2px', background:'linear-gradient(90deg,#f59e0b,#ea6c1e)', borderRadius:'2px', margin:'0 auto 28px' }} />
          <p style={{
            fontSize:'clamp(20px,2.6vw,34px)',
            fontFamily:"'Lora',serif", fontStyle:'italic',
            fontWeight:400, lineHeight:'1.44',
            color:'var(--text)', marginBottom:'22px',
          }}>
            "One of the most transformative investments I made in my adult life."
          </p>
          <p style={{ fontSize:'11px', fontWeight:700, letterSpacing:'0.15em', textTransform:'uppercase', color:'var(--amber)' }}>
            — Neil Sethi, Senior PM at Spotify
          </p>
        </div>
      </section>

      {/* ── CTA ── */}
      <section style={{ padding:'60px 0 100px' }}>
        <div className="container">
          <div style={{
            borderRadius:'22px', padding:'68px 52px',
            textAlign:'center', position:'relative', overflow:'hidden',
            background:'linear-gradient(135deg,#3b1007 0%,#7c2d12 45%,#92400e 100%)',
          }}>
            <div className="orb" style={{ width:300, height:300, top:'-80px', right:'-60px', background:'radial-gradient(circle,rgba(255,255,255,0.07) 0%,transparent 70%)' }} />
            <div className="orb" style={{ width:240, height:240, bottom:'-60px', left:'5%', background:'radial-gradient(circle,rgba(255,255,255,0.04) 0%,transparent 70%)' }} />
            <span className="label" style={{ color:'rgba(255,255,255,0.50)' }}>Start here</span>
            <h2 style={{ fontSize:'clamp(24px,3.5vw,40px)', color:'#fff', marginBottom:'10px', position:'relative', fontStyle:'italic', fontWeight:500 }}>
              Ready to begin?
            </h2>
            <p style={{ color:'rgba(255,255,255,0.65)', marginBottom:'30px', position:'relative', fontSize:'15px' }}>
              Reach out to start a conversation.
            </p>
            <a href="mailto:fayzanrabcoaching@gmail.com" style={{
              display:'inline-block', padding:'13px 28px', borderRadius:'100px',
              background:'rgba(255,255,255,0.15)',
              border:'1.5px solid rgba(255,255,255,0.28)',
              backdropFilter:'blur(10px)',
              color:'#fff', fontSize:'14px', fontWeight:600,
              textDecoration:'none', position:'relative',
              transition:'all 0.22s ease',
            }}
            onMouseEnter={e=>{ e.currentTarget.style.background='rgba(255,255,255,0.25)'; }}
            onMouseLeave={e=>{ e.currentTarget.style.background='rgba(255,255,255,0.15)'; }}
            >
              fayzanrabcoaching@gmail.com
            </a>
          </div>
        </div>
      </section>

    </div>
  );
}
